# pip install openai
from openai import OpenAI

client = OpenAI()  # uses OPENAI_API_KEY from environment

def check_content(text: str) -> dict:
    """Check text against OpenAI's moderation endpoint.
    Returns a dict with flagged boolean and per-category scores.
    """
    response = client.moderations.create(
        model="omni-moderation-latest",
        input=text,
    )
    result = response.results[0]
    return {
        "flagged": result.flagged,
        "categories": {
            cat: getattr(result.categories, cat)
            for cat in [
                "hate", "hate/threatening", "harassment",
                "harassment/threatening", "self-harm",
                "self-harm/intent", "self-harm/instructions",
                "sexual", "sexual/minors",
                "violence", "violence/graphic",
            ]
        },
        "scores": {
            cat: getattr(result.category_scores, cat)
            for cat in [
                "hate", "harassment", "self-harm", "sexual", "violence"
            ]
        },
    }


def safe_chat(user_message: str) -> str:
    """Run moderation on input; if clean, call the chat model."""
    check = check_content(user_message)
    if check["flagged"]:
        flagged_cats = [k for k, v in check["categories"].items() if v]
        return f"Your message was blocked. Reason: {', '.join(flagged_cats)}"

    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[{"role": "user", "content": user_message}],
    )
    reply = response.choices[0].message.content

    # Also moderate the output
    out_check = check_content(reply)
    if out_check["flagged"]:
        return "The response was filtered due to policy constraints."

    return reply


if __name__ == "__main__":
    print(safe_chat("What is the capital of France?"))
